+        FtuiSpan::raw(" | "),
+        FtuiSpan::styled(
+            format!("{} custom", data.stats.rules_custom),
+            FtuiStyle::new().fg(packed(colors.muted)),
+        ),
+        FtuiSpan::raw("    "),
